const systemPrompt = BASE_SYSTEM + `\n\n## Deine Aufgabe: E-Mail entwerfen\nErstelle eine professionelle E-Mail basierend auf dem Projektkontext.\n\nRegeln:\n- Professionell aber nicht steif\n- Verwende die Anrede der Zielperson (Pseudonym wird nachher durch echten Namen ersetzt)\n- Beziehe dich auf konkrete Projektereignisse (offene AP, Meilensteine, Risiken)\n- KEINE kundenbezogenen Daten erfinden — nutze nur was im Kontext steht\n- Biete verschiedene Tonalitaeten an wenn sinnvoll\n\nAntwortformat (STRIKT JSON):\n{ "betreff": "<Betreffzeile>", "empfaenger": "<Person-Pseudonym>", "text": "<Vollstaendiger E-Mail-Text>", "hinweise": "<Optionale Hinweise zum Anpassen>" }`;

const userPrompt = (function(ctx) {
      let msg = 'Heute ist ' + ctx.heute + '.\n';
      if (ctx.fokus_projekt) msg += 'Projekt: ' + ctx.fokus_projekt.name + '\n';
      const aps = (ctx.fokus_aps || ctx.arbeitspakete || []).filter(a => a.status !== 'erledigt');
      if (aps.length) {
        msg += '\nOffene AP:\n';
        aps.forEach(a => { msg += '- ' + a.titel + ' | Status: ' + a.status + ' | Deadline: ' + (a.deadline || 'keine') + '\n'; });
      }
      if (ctx.meilensteine?.length) {
        msg += '\nMeilensteine:\n';
        ctx.meilensteine.forEach(m => { msg += '- ' + m.titel + ' | ' + m.datum + ' | ' + m.status + '\n'; });
      }
      if (ctx.personen?.length) {
        msg += '\nVerfuegbare Kundenansprechpartner/Personen:\n';
        ctx.personen.forEach(p => { msg += '- ' + p.name + (p.rolle ? ' (Rolle: ' + p.rolle + ')' : '') + '\n'; });
      }
      msg += '\nErstelle einen E-Mail-Entwurf fuer dieses Projekt.';
      if (ctx.anlass) msg += ' Anlass: ' + ctx.anlass;
      return msg;
    })(ctx);

return { json: { action: 'draft_email', systemPrompt: systemPrompt, userPrompt: userPrompt, context: ctx } };

// Parse AI output to JSON
const input = $input.first().json;
let aiOutput = input.output || input.text || '';
let parsed = null;
try { parsed = JSON.parse(aiOutput); } catch (e) {
  const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)\s*```/) || aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) { try { parsed = JSON.parse(jsonMatch[1] || jsonMatch[0]); } catch (e2) {
    try { let fixed = (jsonMatch[1] || jsonMatch[0]).replace(/,\s*}/g, '}').replace(/,\s*]/g, ']'); parsed = JSON.parse(fixed); } catch (e3) {} } }
}
if (parsed) return { json: parsed };
return { json: { zusammenfassung: aiOutput, _raw: true } };
